var e=[{id:`L2_1`,type:`dialog`,speaker:`YOONA_CODEX_SPECIAL_NULL`,text:{KOREA:`천사와 인간이 이렇게 친해진 건 우리가 최초일 거야! 할머니가 알면 깜짝 놀라시겠지?`,JPN:`天使と人間がこんなに仲良くなったのは私たちが初めてかも！　お婆ちゃんが知ったらびっくりすると思うよ？`,ENG:`This must be the first time an angel and a human have become so close! I bet Grandma will be so surprised!`,TWN:`天使和人類能這麼親近，我們可能是第一個！`},stage:{bg:`SKY`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOONA_CODEX_SPECIAL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`YOONA_CODEX_SPECIAL_NULL`,text:{KOREA:`앗, 할머니한테는 달링을 뭐라고 소개하면 좋을까? 서로를 평생 책임지기로 약속한 계약관계?`,JPN:`あっ、お婆ちゃんにはダーリンを何て紹介したらいいかな？　お互いに一生の責任を負うことを約束した契約関係？`,ENG:`Oh, how should I introduce you to Grandma? A contractual relationship in which we promise to take responsibility for each other forever?`,TWN:`奶奶應該會嚇一大跳吧？那個，我該怎麼跟奶奶介紹達令呢？是承諾要對彼此一生負責的契約關係？`},stage:{bg:`SKY`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOONA_CODEX_SPECIAL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`YOONA_CODEX_SPECIAL_NULL`,text:{KOREA:`*꾸짖는 지저귐* 에? 혼날 거라고요? 그치만 친구보단 특별한 표현을 쓰고 싶었는데...!`,JPN:`*叱るさえずり*　え？ 怒られるって？　でも友達より特別な言い方をしたいだけなのに……！`,ENG:`*Scolding chirps* Huh? She'll scold me if I say that? But I wanted to use a special expression instead of just friend..!`,TWN:`蛤？這樣會被罵喔？可是人家想用比朋友還特別的關係來表達…！`},stage:{bg:`SKY`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOONA_CODEX_SPECIAL_NULL`,face:`UNIT_DESPAIR`},R:null}}}];export{e as default};